+'use strict';
+
+const path = require('path');
+
+/**
+ * Safely resolve a path within a base directory to prevent path traversal
+ * @param {string} baseDir - The base directory that should contain the file
+ * @param {string} userPath - User-provided path (potentially malicious)
+ * @returns {string|null} - Safe resolved path or null if traversal detected
+ */
+function safeResolve(baseDir, userPath) {
+  // Normalize and resolve to absolute paths
+  const resolvedBase = path.resolve(baseDir);
+  const resolvedPath = path.resolve(baseDir, userPath);
+  
+  // Ensure the resolved path is within the base directory
+  // Using path.relative to check if path escapes
+  const relative = path.relative(resolvedBase, resolvedPath);
+  
+  if (relative.startsWith('..') || path.isAbsolute(relative)) {
+    return null;
+  }
+  return resolvedPath;
+}
+
+module.exports = { safeResolve };
