+/**
+ * Sanitizes user input by stripping HTML tags.
+ * This prevents XSS attacks when user input is rendered in email templates or other contexts.
+ */
+
+/**
+ * Strips HTML tags from a string value.
+ * @param {*} value - The value to sanitize
+ * @returns {*} - The sanitized value (strings have HTML tags removed)
+ */
+export function stripHtmlTags(value) {
+  if (typeof value !== 'string') return value;
+  return value.replace(/<[^>]*>/g, '');
+}
+
+/**
+ * Sanitizes all string values in a metadata object by stripping HTML tags.
+ * @param {Object} metadata - The user metadata object
+ * @returns {Object} - Sanitized metadata object
+ */
+export function sanitizeUserMetadata(metadata) {
+  if (!metadata || typeof metadata !== 'object') return metadata;
+  
+  const result = {};
+  for (const key in metadata) {
+    if (Object.prototype.hasOwnProperty.call(metadata, key)) {
+      result[key] = stripHtmlTags(metadata[key]);
+    }
+  }
+  return result;
+}
